{
  "domain_analysis": {
    "business_context": "A logistics platform managing the lifecycle of parcel deliveries, from shipment creation through transit to final delivery. The platform enforces state machine integrity, physical weight constraints, and a tiered pricing model based on weight brackets.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and weight-bracket classification for billing.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, governed by a state machine and weight constraints." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected. Required at shipment creation." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel must be delivered. Required at shipment creation." },
      { "term": "Pending", "definition": "The initial state of a shipment after creation, before it enters transit." },
      { "term": "In Transit", "definition": "The state indicating the shipment has been picked up and is en route to the delivery address." },
      { "term": "Delivered", "definition": "The terminal state indicating the shipment has reached its delivery address. Irreversible." },
      { "term": "Weight Bracket", "definition": "A classification tier derived from shipment weight that determines the billing rate. Three tiers: Standard, Heavy, and Freight." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing > 0 kg and ≤ 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing > 10 kg and ≤ 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing > 50 kg and ≤ 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is logically meaningless — it cannot be routed, priced, or fulfilled. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions follow a strict forward-only machine: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Backward transitions (e.g., In Transit → Pending) would corrupt operational state — dispatched drivers cannot be un-dispatched, scans cannot be un-scanned. This is state integrity.",
      "testable_assertion": "A shipment in state 'In Transit' cannot transition to 'Pending'. A shipment in state 'Delivered' cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed once a shipment is Delivered.",
      "invariant": true,
      "invariant_justification": "Delivery is a legally and operationally final event — it triggers proof-of-delivery, invoicing, and SLA closure. Reversing it would corrupt billing, audit trails, and customer records.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment must be rejected, regardless of the target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "A zero or negative weight is physically impossible for a real parcel. Exceeding 1000 kg exceeds the physical handling capacity of the platform's logistics infrastructure. These are physical constraints.",
      "testable_assertion": "A shipment with weight ≤ 0 or weight > 1000 must be rejected at creation and at any update point."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard for weight > 0 and ≤ 10 kg, Heavy for weight > 10 and ≤ 50 kg, Freight for weight > 50 and ≤ 1000 kg.",
      "invariant": false,
      "invariant_justification": "Weight bracket thresholds are a pricing policy. A VP of pricing could adjust the boundaries (e.g., move Heavy to 15 kg) without corrupting system state. The system must support brackets, but the specific thresholds are policy.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment starts in Pending state.",
      "invariant": true,
      "invariant_justification": "A shipment cannot be born In Transit or Delivered — that would bypass pickup scanning and operational sequencing. Initial state is a state machine integrity constraint.",
      "testable_assertion": "Upon successful creation, a shipment's state must be Pending."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address, delivery address, and weight of 5 kg",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment with a missing pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment with a missing delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment transitions to In Transit",
      "then": "The state is updated to In Transit and the transition is recorded"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The system rejects the transition and the shipment remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "The shipment transitions to Delivered",
      "then": "The state is updated to Delivered and no further transitions are permitted"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state transition is attempted (to Pending, In Transit, or any other state)",
      "then": "The system rejects the transition and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A request to create a shipment with weight of 0 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A request to create a shipment with weight of -5 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-10",
      "given": "A request to create a shipment with weight of 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight cannot exceed 1000 kg"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight exactly 10 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Standard"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight exactly 50 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-14",
      "given": "A shipment with weight of 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Freight"
    },
    {
      "id": "AC-15",
      "given": "A shipment with weight exactly 1000 kg",
      "when": "The creation is attempted",
      "then": "The shipment is created successfully and classified as Freight"
    }
  ],

  "edge_cases": [
    { "scenario": "Shipment created with weight at exact boundary of 10 kg", "expected_behavior": "Classified as Standard (upper bound inclusive for the lower bracket per '0-10 kg is standard')." },
    { "scenario": "Shipment created with weight at exact boundary of 50 kg", "expected_behavior": "Classified as Heavy (upper bound inclusive for '10-50 kg is heavy')." },
    { "scenario": "Shipment created with weight exactly 1000 kg", "expected_behavior": "Accepted and classified as Freight — the max weight is a ≤ constraint, not strictly less than." },
    { "scenario": "Attempt to transition directly from Pending to Delivered, skipping In Transit", "expected_behavior": "Spec does not explicitly address this. Likely should be rejected — a parcel cannot be delivered without first being in transit. Flagged as ambiguity." },
    { "scenario": "Weight provided as a floating-point value very close to zero (e.g., 0.001 kg)", "expected_behavior": "Accepted — weight is positive. However, this may be operationally nonsensical; the spec does not define a practical minimum." },
    { "scenario": "Shipment created with identical pickup and delivery addresses", "expected_behavior": "Spec does not prohibit this. The system should accept it, though it may be a data entry error worth flagging in the UI." },
    { "scenario": "Concurrent state transition attempts on the same shipment", "expected_behavior": "Only one transition should succeed. The system must enforce state machine integrity under concurrency — optimistic locking or similar." }
  ],

  "business_impact": {
    "financial": "Weight bracket misclassification directly impacts revenue — undercharging Heavy as Standard or Freight as Heavy loses margin. Correct bracket enforcement is a billing integrity concern.",
    "operational": "State machine enforcement prevents operational chaos — a driver cannot be dispatched to a parcel that was retroactively set back to Pending, and delivered parcels triggering re-delivery would waste fleet resources.",
    "user": "Customers expect delivery finality — once a shipment shows Delivered, it must stay Delivered. Reverting state would undermine trust and cause confusion in tracking UIs.",
    "risk": "Primary risks are (1) state corruption leading to ghost shipments or lost parcels, (2) billing errors from incorrect weight bracket classification, and (3) audit trail gaps if Delivered status can be reversed post-invoicing.",
    "stakeholders_affected": [
      { "group": "Shippers (Customers)", "impact": "Rely on accurate state tracking for visibility. Weight limits and pricing brackets affect their cost expectations." },
      { "group": "Operations / Dispatch", "impact": "State machine integrity drives dispatch workflows. Backward transitions would create phantom pickups and routing errors." },
      { "group": "Finance / Billing", "impact": "Weight brackets directly determine invoice line items. Misclassification is a revenue leakage vector." },
      { "group": "Drivers / Couriers", "impact": "Depend on correct state to know what to pick up and deliver. Corrupt state means wasted trips." },
      { "group": "Customer Support", "impact": "Delivered-is-final simplifies dispute resolution. If state could revert, support escalations increase." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core rules (state machine, weight range, brackets) but leaves several edge cases ambiguous: whether Pending→Delivered skip is allowed, whether weight can be changed after creation, boundary inclusivity of bracket ranges, and what constitutes a valid address. The bracket boundaries use informal notation ('0-10', '10-50', 'over 50') which creates ambiguity at exact boundary values (is 10 kg Standard or Heavy?). I've applied standard logistics interpretation (inclusive upper bounds) but this should be confirmed.",
    "high_confidence_areas": [
      "Delivered is a terminal state — unambiguous",
      "In Transit cannot revert to Pending — explicitly stated",
      "Weight must be positive and ≤ 1000 kg — clearly stated",
      "Both addresses required at creation — clearly stated",
      "Three weight brackets exist with approximate boundaries"
    ],
    "low_confidence_areas": [
      "Exact boundary inclusivity of weight brackets (is 10 kg Standard or Heavy?)",
      "Whether Pending → Delivered direct transition is allowed or must go through In Transit",
      "Whether weight can be modified after shipment creation",
      "What constitutes a valid address (format, completeness, geocodability)",
      "Whether additional states exist (e.g., Cancelled, Failed Delivery, Returned)"
    ],
    "assumptions": [
      "Weight bracket boundaries are inclusive on the upper bound: 0-10 means (0, 10], 10-50 means (10, 50], over 50 means (50, 1000]",
      "Shipments must transition through In Transit before reaching Delivered (no skip allowed)",
      "Initial state of a new shipment is always Pending",
      "Weight is set at creation time and the spec does not address post-creation weight changes",
      "There are no other shipment states beyond Pending, In Transit, and Delivered in this bounded context"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec uses informal bracket notation ('0-10 kg', '10-50 kg', 'over 50 kg') which is ambiguous at exact boundaries. Is a 10 kg parcel Standard or Heavy? Is a 50 kg parcel Heavy or Freight? Standard logistics practice would use inclusive upper bounds, but this must be confirmed to avoid billing disputes.",
      "affected_stakeholders": ["Finance / Billing", "Shippers (Customers)"],
      "options": ["Standard: (0,10], Heavy: (10,50], Freight: (50,1000] — inclusive upper bounds", "Standard: (0,10), Heavy: [10,50), Freight: [50,1000] — inclusive lower bounds"],
      "recommendation": "Use inclusive upper bounds: Standard ≤ 10, Heavy ≤ 50, Freight ≤ 1000. This is conventional in logistics pricing and favors the customer at boundaries."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not state whether a shipment can transition directly from Pending to Delivered, skipping In Transit. In real logistics, this should not be possible — a parcel must be picked up before it can be delivered. But some edge cases (e.g., same-location pickup and delivery) might warrant it.",
      "affected_stakeholders": ["Operations / Dispatch", "Drivers / Couriers"],
      "options": ["Enforce strict Pending → In Transit → Delivered sequence with no skipping", "Allow Pending → Delivered for special cases"],
      "recommendation": "Enforce strict sequential transitions. A Pending → Delivered skip would bypass pickup confirmation, driver assignment, and scan events — creating audit gaps."
    },
    {
      "type": "missing_context",
      "description": "The spec does not mention a Cancelled state. In real logistics, shipments are routinely cancelled before pickup. Without a Cancelled state, the only way to handle cancellation is to leave a shipment in Pending forever or delete it, both of which are operationally problematic.",
      "affected_stakeholders": ["Shippers (Customers)", "Customer Support", "Finance / Billing"],
      "options": ["Add a Cancelled state reachable only from Pending", "Handle cancellation outside the shipment state machine", "Defer — out of scope for this iteration"],
      "recommendation": "Clarify with product manager. A Cancelled state reachable from Pending is standard in logistics and should likely be included."
    }
  ],

  "rejection_reasons": []
}

